import { useEffect, useState } from 'react';
import { getDashboard, getAllStock } from '../services/stockApi';
import { Package, Warehouse, BarChart3, Layers } from 'lucide-react';
import Spinner from '../components/Spinner';
import toast from 'react-hot-toast';

export default function Dashboard() {
  const [stats,  setStats]  = useState(null);
  const [stocks, setStocks] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    Promise.all([getDashboard(), getAllStock()])
      .then(([d, s]) => { setStats(d.data); setStocks(s.data); })
      .catch(() => toast.error('Erreur chargement dashboard'))
      .finally(() => setLoading(false));
  }, []);

  if (loading) return <div className="page"><Spinner /></div>;

  const statCards = [
    { icon: <Package />, label: 'Produits',       value: stats?.totalProducts,   color: '#3b82f6', bg: 'rgba(59,130,246,0.12)'  },
    { icon: <Warehouse />, label: 'Entrepôts',    value: stats?.totalWarehouses, color: '#10b981', bg: 'rgba(16,185,129,0.12)'  },
    { icon: <Layers />, label: 'Lignes de stock', value: stats?.totalStockLines, color: '#f59e0b', bg: 'rgba(245,158,11,0.12)'  },
    { icon: <BarChart3 />, label: 'Qté totale',   value: stats?.totalQuantity,   color: '#a78bfa', bg: 'rgba(139,92,246,0.12)'  },
  ];

  // Top 5 produits par quantité
  const topStocks = [...stocks]
    .sort((a, b) => b.quantity - a.quantity)
    .slice(0, 8);

  // Alertes stock faible (< 10)
  const lowStock = stocks.filter(s => s.quantity < 10);

  return (
    <div className="page">
      <div className="page-header">
        <div>
          <h2>Dashboard</h2>
          <p>Vue d'ensemble des stocks en temps réel</p>
        </div>
      </div>

      <div className="stat-grid">
        {statCards.map(({ icon, label, value, color, bg }) => (
          <div className="stat-card" key={label}>
            <div className="stat-icon" style={{ background: bg, color }}>
              {icon}
            </div>
            <div>
              <h3>{value ?? '—'}</h3>
              <p>{label}</p>
            </div>
          </div>
        ))}
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 20 }}>
        {/* Top stocks */}
        <div className="card">
          <h3 style={{ fontSize: 14, fontWeight: 600, marginBottom: 16 }}>
            Top stocks — quantités les plus élevées
          </h3>
          <div className="table-wrap">
            <table>
              <thead>
                <tr>
                  <th>Produit</th>
                  <th>Entrepôt</th>
                  <th>Qté</th>
                </tr>
              </thead>
              <tbody>
                {topStocks.map(s => (
                  <tr key={s.stockId}>
                    <td>{s.productName}</td>
                    <td><span className="badge badge-blue">{s.warehouseName}</span></td>
                    <td>
                      <span className={`qty ${s.quantity < 10 ? 'qty-low' : s.quantity < 30 ? 'qty-medium' : 'qty-ok'}`}>
                        {s.quantity}
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>

        {/* Alertes */}
        <div className="card">
          <h3 style={{ fontSize: 14, fontWeight: 600, marginBottom: 16, color: 'var(--danger)' }}>
            ⚠️ Alertes stock faible (&lt; 10 unités)
          </h3>
          {lowStock.length === 0 ? (
            <div className="empty">
              <p style={{ color: 'var(--success)' }}>✓ Tous les stocks sont suffisants</p>
            </div>
          ) : (
            <div className="table-wrap">
              <table>
                <thead><tr><th>Produit</th><th>Entrepôt</th><th>Qté</th></tr></thead>
                <tbody>
                  {lowStock.map(s => (
                    <tr key={s.stockId}>
                      <td>{s.productName}</td>
                      <td>{s.warehouseName}</td>
                      <td><span className="qty qty-low">{s.quantity}</span></td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
